@layer reset, base, components;

@layer reset {
  * { box-sizing: border-box; }
}

@layer base {
  button { font: inherit; }
}

@layer components {
  .button { background: #123; color: white; }
}

button[aria-pressed="true"] { color: gold; }

.card > h2 + p::first-line {
  font-weight: 700;
}

button:is(:hover, :focus-visible) {
  outline: 2px solid currentColor;
}

[aria-expanded="true"] > .chevron {
  transform: rotate(180deg);
}

:where(nav a) {
  text-decoration: none;
}

@layer tokens, base, components;

@layer tokens {
  :root {
    --surface: #111827;
    --surface-elevated: #1f2937;
    --text: #f9fafb;
  }
}

@layer base {
  body {
    background: var(--surface);
    color: var(--text);
  }
}

@layer components {
  .panel {
    background: var(--surface-elevated);
    color: var(--text);
  }
}

@scope (.panel) {
  button {
    color: inherit;
  }
}

.card {
  box-sizing: border-box;
  width: min(100%, 28rem);
  padding: 1rem;
  border: 1px solid #374151;
  position: relative;
  overflow: clip;
}

.card .badge {
  position: absolute;
  top: 0.75rem;
  right: 0.75rem;
}

.card .sticky-note {
  position: sticky;
  top: 0;
}

.toolbar {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.toolbar__search {
  flex: 1 1 20rem;
  min-width: 0;
}

.toolbar__actions {
  margin-inline-start: auto;
  display: flex;
  gap: 0.5rem;
}

.card-grid {
  display: grid;
  gap: 1.5rem;
  grid-template-columns: repeat(auto-fit, minmax(14rem, 1fr));
}

.card {
  display: grid;
  gap: 0.75rem;
  grid-template-rows: auto auto 1fr;
}

.card__meta {
  grid-column: 1 / -1;
}

.card__detail {
  display: grid;
  grid-template-columns: subgrid;
  grid-column: 1 / -1;
}

.layout {
  padding-block: clamp(1rem, 3vw, 2rem);
  padding-inline: clamp(1rem, 4vw, 2rem);
}

.panel {
  container-type: inline-size;
}

.panel__body {
  display: grid;
  gap: 1rem;
}

@media (width >= 60rem) {
  .layout {
    grid-template-columns: 18rem minmax(0, 1fr);
  }
}

@container (width > 32rem) {
  .panel__body {
    grid-template-columns: 12rem minmax(0, 1fr);
  }
}

.feature-card {
  color: oklch(0.22 0.03 250);
  background: linear-gradient(135deg, oklch(0.98 0.02 250), oklch(0.92 0.03 270));
  border: 1px solid oklch(0.84 0.04 250);
  border-radius: 1.25rem;
  box-shadow: 0 18px 40px oklch(0.2 0.02 250 / 0.12);
  padding: clamp(1.25rem, 3vw, 2rem);
}

.feature-card h3 {
  font-size: clamp(1.25rem, 2vw, 1.75rem);
  line-height: 1.15;
  text-wrap: balance;
}

.feature-card p {
  line-height: 1.6;
  max-width: 60ch;
}
